mapper.select:
SELECT d.id AS delivery_id, d.job_id, COALESCE(d.status, 0) AS status, d.feedback, CASE WHEN p.status = 1 THEN COALESCE(a.resume_url, d.resume_url) ELSE NULL END AS resume_url, p.status AS attachment_status, CASE WHEN COALESCE(a.resume_url, d.resume_url) IS NULL OR COALESCE(a.resume_url, d.resume_url) = '' THEN 0 ELSE 1 END AS has_resume_attachment, i.schedule_time AS interview_time, i.location AS interview_location, i.method AS interview_method, i.remark AS interview_remark, i.status AS interview_status, d.create_time, j.title AS job_title, u.id AS applicant_id, u.nickname AS applicant_nickname, u.avatar AS applicant_avatar, a.real_name AS applicant_real_name, a.gender, a.work_years, a.college AS college, a.college AS collage, a.degree, a.phone AS applicant_phone, a.email AS applicant_email, a.current_identity, a.current_status, a.expect_city, a.expect_job, a.expect_salary, a.skills, a.advantage, a.education_json, a.experience_json, a.project_json, a.certificate_json, a.award_json, a.language_json, TIMESTAMPDIFF(YEAR, a.birthday, CURDATE()) AS age FROM job_apply d JOIN job_post j ON d.job_id = j.id JOIN sys_user u ON d.applicant_id = u.id LEFT JOIN applicant_profile a ON u.id = a.user_id LEFT JOIN resume_attachment_permission p ON p.applicant_id = d.applicant_id AND p.merchant_id = j.merchant_id AND p.attachment_type = 'RESUME' LEFT JOIN ( SELECT s1.* FROM job_interview s1 JOIN ( SELECT delivery_id, MAX(round_no) AS max_round FROM job_interview GROUP BY delivery_id ) s2 ON s1.delivery_id = s2.delivery_id AND s1.round_no = s2.max_round ) i ON i.delivery_id = d.id WHERE j.merchant_id = #{merchantId}
AND d.job_id = #{jobId}
AND COALESCE(d.status, 0) = #{status}
AND a.degree = #{degree}
ORDER BY d.create_time DESC

SELECT d.id, d.job_id AS jobId, COALESCE(d.status, 0) AS status, d.feedback, i.schedule_time AS interviewTime, i.location AS interviewLocation, i.method AS interviewMethod, i.remark AS interviewRemark, i.status AS interviewStatus, d.create_time AS createTime, j.title AS jobTitle, j.work_location AS workLocation, j.min_salary AS minSalary, j.max_salary AS maxSalary, CONCAT(j.min_salary, 'k-', j.max_salary, 'k') AS salaryRange, m.company_name AS companyName, j.status AS jobStatus, j.audit_status AS jobAuditStatus FROM job_apply d LEFT JOIN job_post j ON d.job_id = j.id LEFT JOIN merchant_profile m ON j.merchant_id = m.user_id LEFT JOIN ( SELECT s1.* FROM job_interview s1 JOIN ( SELECT delivery_id, MAX(round_no) AS max_round FROM job_interview GROUP BY delivery_id ) s2 ON s1.delivery_id = s2.delivery_id AND s1.round_no = s2.max_round ) i ON i.delivery_id = d.id WHERE d.applicant_id = #{userId}
AND COALESCE(d.status, 0) = #{status}
AND ( j.title LIKE CONCAT('%', #{keyword}, '%') OR m.company_name LIKE CONCAT('%', #{keyword}, '%') OR j.work_location LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY d.create_time ASC
ORDER BY d.create_time DESC
